[][302] +    // Method Description:
[][303] +    // - Open a new tab. This will create the TerminalControl hosting the
[][304] +    //      terminal, and add a new Tab to our list of tabs. The method can
[][305] +    //      optionally be provided a profile index, which will be used to create
[][306] +    //      a tab using the profile in that index.
[][307] +    //      If no index is provided, the default profile will be used.
[][308] +    // Arguments:
[][309] +    // - profileIndex: an optional index into the list of profiles to use to
[][310] +    //      initialize this tab up with.
[][311] +    void TerminalPage::_OpenNewTab(std::optional<int> profileIndex)
[][312] +    {
[][313] +        GUID profileGuid;
[][314] +
[][315] +        if (profileIndex)
[][316] +        {
[][317] +            const auto realIndex = profileIndex.value();
[][318] +            const auto profiles = _settings->GetProfiles();
[][319] +
[][320] +            // If we don't have that many profiles, then do nothing.
[][321] +            if (realIndex >= gsl::narrow<decltype(realIndex)>(profiles.size()))
[][322] +            {
[][323] +                return;
[][324] +            }
[][325] +
[][326] +            const auto& selectedProfile = profiles[realIndex];
[][327] +            profileGuid = selectedProfile.GetGuid();
[][328] +        }
[][329] +        else
[][330] +        {
[][331] +            // Getting Guid for default profile
[][332] +            const auto globalSettings = _settings->GlobalSettings();
[][333] +            profileGuid = globalSettings.GetDefaultProfile();
[][334] +        }
[][335] +
[][336] +        TerminalSettings settings = _settings->MakeSettings(profileGuid);
[][337] +        _CreateNewTabFromSettings(profileGuid, settings);
[][338] +
[][339] +        const int tabCount = static_cast<int>(_tabs.size());
[][340] +        TraceLoggingWrite(
[][341] +            g_hTerminalAppProvider, // handle to TerminalApp tracelogging provider
[][342] +            "TabInformation",
[][343] +            TraceLoggingDescription("Event emitted upon new tab creation in TerminalApp"),
[][344] +            TraceLoggingInt32(tabCount, "TabCount", "Count of tabs curently opened in TerminalApp"),
[][345] +            TraceLoggingBool(profileIndex.has_value(), "ProfileSpecified", "Whether the new tab specified a profile explicitly"),
[][346] +            TraceLoggingGuid(profileGuid, "ProfileGuid", "The GUID of the profile spawned in the new tab"),
[][347] +            TraceLoggingKeyword(MICROSOFT_KEYWORD_MEASURES),
[][348] +            TelemetryPrivacyDataTag(PDT_ProductAndServicePerformance));
[][349] +    }
