[][351] +    // Method Description:
[][352] +    // - Creates a new tab with the given settings. If the tab bar is not being
[][353] +    //      currently displayed, it will be shown.
[][354] +    // Arguments:
[][355] +    // - settings: the TerminalSettings object to use to create the TerminalControl with.
[][356] +    void TerminalPage::_CreateNewTabFromSettings(GUID profileGuid, TerminalSettings settings)
[][357] +    {
[][358] +        // Initialize the new tab
[][359] +
[][360] +        // Create a connection based on the values in our settings object.
[][361] +        const auto connection = _CreateConnectionFromSettings(profileGuid, settings);
[][362] +
[][363] +        TermControl term{ settings, connection };
[][364] +
[][365] +        // Add the new tab to the list of our tabs.
[][366] +        auto newTab = _tabs.emplace_back(std::make_shared<Tab>(profileGuid, term));
[][367] +
[][368] +        const auto* const profile = _settings->FindProfile(profileGuid);
[][369] +
[][370] +        // Hookup our event handlers to the new terminal
[][371] +        _RegisterTerminalEvents(term, newTab);
[][372] +
[][373] +        auto tabViewItem = newTab->GetTabViewItem();
[][374] +        _tabView.Items().Append(tabViewItem);
[][375] +
[][376] +        // Set this profile's tab to the icon the user specified
[][377] +        if (profile != nullptr && profile->HasIcon())
[][378] +        {
[][379] +            newTab->UpdateIcon(profile->GetExpandedIconPath());
[][380] +        }
[][381] +
[][382] +        tabViewItem.PointerPressed({ this, &TerminalPage::_OnTabClick });
[][383] +
[][384] +        // When the tab is closed, remove it from our list of tabs.
[][385] +        newTab->Closed([tabViewItem, this]() {
[][386] +            _tabView.Dispatcher().RunAsync(CoreDispatcherPriority::Normal, [tabViewItem, this]() {
[][387] +                _RemoveTabViewItem(tabViewItem);
[][388] +            });
[][389] +        });
[][390] +
[][391] +        // This is one way to set the tab's selected background color.
[][392] +        //   tabViewItem.Resources().Insert(winrt::box_value(L"TabViewItemHeaderBackgroundSelected"), a Brush?);
[][393] +
[][394] +        // This kicks off TabView::SelectionChanged, in response to which we'll attach the terminal's
[][395] +        // Xaml control to the Xaml root.
[][396] +        _tabView.SelectedItem(tabViewItem);
[][397] +    }
