[][639] +    {
[][640] +        // Add an event handler when the terminal's selection wants to be copied.
[][641] +        // When the text buffer data is retrieved, we'll copy the data into the Clipboard
[][642] +        term.CopyToClipboard({ this, &TerminalPage::_CopyToClipboardHandler });
[][643] +
[][644] +        // Add an event handler when the terminal wants to paste data from the Clipboard.
[][645] +        term.PasteFromClipboard({ this, &TerminalPage::_PasteFromClipboardHandler });
[][646] +
[][647] +        // Don't capture a strong ref to the tab. If the tab is removed as this
[][648] +        // is called, we don't really care anymore about handling the event.
[][649] +        std::weak_ptr<Tab> weakTabPtr = hostingTab;
[][650] +        term.TitleChanged([this, weakTabPtr](auto newTitle) {
[][651] +            auto tab = weakTabPtr.lock();
[][652] +            if (!tab)
[][653] +            {
[][654] +                return;
[][655] +            }
[][656] +            // The title of the control changed, but not necessarily the title
[][657] +            // of the tab. Get the title of the focused pane of the tab, and set
[][658] +            // the tab's text to the focused panes' text.
[][659] +            _UpdateTitle(tab);
[][660] +        });
[][661] +
[][662] +        term.GotFocus([this, weakTabPtr](auto&&, auto&&) {
[][663] +            auto tab = weakTabPtr.lock();
[][664] +            if (!tab)
[][665] +            {
[][666] +                return;
[][667] +            }
[][668] +            // Update the focus of the tab's panes
[][669] +            tab->UpdateFocus();
[][670] +
[][671] +            // Possibly update the title of the tab, window to match the newly
[][672] +            // focused pane.
[][673] +            _UpdateTitle(tab);
[][674] +
[][675] +            // Possibly update the icon of the tab.
[][676] +            _UpdateTabIcon(tab);
[][677] +        });
[][678] +    }
